var faq={init:function(){$("#i_dialog_question_dome").click(function(){faq.questionAdd()});$("#i_dialog_question").on("hidden.bs.modal",function(){location.reload()});$(".c-button-answer").click(function(){var a=$(this);$.ajax({type:"post",dataType:"json",data:$(this).parent().parent().parent().serialize(),beforeSend:function(){$(a).prop("disable",true)},success:function(b){if(b.success){location.reload()}else{$(a).html("Не удалось отправить вопрос")}},error:function(){$(a).html("Не удалось отправить вопрос")}})});$(".c-button-done").click(function(){var a=$(this);$.ajax({type:"post",dataType:"json",data:{action:"done",qId:$(a).data("qId")},beforeSend:function(){$(a).prop("disable",true)},success:function(b){if(b.success){location.reload()}else{$(a).html("Не удалось отправить вопрос")}},error:function(){$(a).html("Не удалось отправить вопрос")}})})},questionAdd:function(){$.ajax({type:"post",dataType:"json",data:$("#i_dialog_question_form").serialize(),beforeSend:function(){$("#i_dialog_question_progress").show()},success:function(a){if(a.success){$("#i_dialog_question_form").hide();$("#i_dialog_question_error").removeClass("alert alert-danger").addClass("alert alert-success").html(a.errorText)}else{$("#i_dialog_question_error").removeClass("alert alert-success").addClass("alert alert-danger").html(a.errorText)}},complete:function(){$("#i_dialog_question_dome").hide();$("#i_dialog_question_progress").hide()},error:function(){$("#i_dialog_question_error").removeClass("alert alert-success").addClass("alert alert-danger").html("Не удалось выполнить запрос.")}})}};$(document).ready(function(){faq.init()});